import * as t from "io-ts";
import { SuiStakingIntent } from "./suiStakingIntent";

/**
 * @title Walrus Stake Intent
 *
 * @param {string} sharedStakingObjectId - The staking object id
 */
export const WalrusStakingIntent = t.intersection([
  SuiStakingIntent,
  t.type({
    sharedStakingObjectId: t.string,
  }),
]);

export type WalrusStakingIntent = t.TypeOf<typeof WalrusStakingIntent>;
